public String mixString(String a, String b)
{
    int aLength = a.length();
    int bLength = b.length();

    int max = Math.max(aLength, bLength);

    String result = "";

    for (int i = 0; i < max; i++)
    {
        if (i <= aLength - 1)
        {
            result += a.substring(i, i + 1);
        }
        if (i <= bLength - 1)
        {
            result += b.substring(i, i + 1);
        }
    }

    return result;
}

