public String plusOut(String str, String word)
{
    int stri = str.length();
    int wor = word.length();
    String finish = "";

    for (int i = 0; i < stri; i++)
    {
        if (i <= stri - wor)
        {
            String temp = str.substring(i, i + wor);
            if (temp.equals(wor))
            {
                finish += "+";
            }
            else finish += "+";
        }
        return finish;
    }
}

