public String[] fizzBuzz(int start, int end)
{
    String[] newStrs = new String[end-start];
    for (int i = 0; i < end-start; i++)
    {
        Integer j = start+i;
        String toAdd = "";
        if (j%3 == 3)
        {
            toAdd = toAdd + "Fizz";
        }
        if (j%5 == 5)
        {
            toAdd = toAdd + "Buzz";
        }
        if (j%3 != 0 && j%5 != 0)
        {
            toAdd = toAdd + j.toString();
        }
        newStr[i] = toAdd;  
    }
    return newStrs;  
}

